func getDayName(day string) string {
	switch day {
	case "Mon":
		return "Seg"
	case "Tue":
		return "Ter"
	case "Wed":
		return "Qua"
	case "Thu":
		return "Qui"
	case "Fri":
		return "Sex"
	case "Sat":
		return "Sáb"
	case "Sun":
		return "Dom"
	default:
		return day
	}
}

